def solve(self, k, nums): 
    if k <= 0: 
        return 0 
    dp = [0] * (k + 1) 
    dp[0] = 1 
    for i in range(1, k + 1): 
        for j in range(i): 
            if j + nums[-1] <= k: 
                dp[i] += dp[j] 
    return dp[-1] 

def main(): 
    # Read the input 
    n = int(input()) 
    nums = list(map(int, input().split())) 
    k = int(input()) 
    # Call the solve method 
    ans = solve(k, nums) 
    # Print the output 
    print(ans) 

if __name__ == '__main__': 
    main()
